    <text x="50" y="118" fill="#e4e4e7" font-size="28" font-weight="700">Up to 55%</text>
    <text x="50" y="145" fill="#a1a1aa" font-size="13">45% national + 10% resident tax</text>
    <text x="50" y="170" fill="#a1a1aa" font-size="13">Progressive, combined with other income</text>
    <text x="50" y="195" fill="#a1a1aa" font-size="13">No loss carryforward</text>
    <text x="50" y="250" fill="#71717a" font-size="12">No ETF listing possible (PSA regime)</text>
    <rect x="380" y="55" width="290" height="230" rx="10" fill="#0e2a1e" stroke="#4ade80" stroke-width="1.3"/>
    <text x="400" y="85" fill="#86efac" font-size="15" font-weight="700">Proposed: separate tax (like stocks)</text>
