<div class="es">
<svg viewBox="0 0 700 420" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
  <text x="20" y="32" fill="#fafafa" font-size="16" font-weight="700" font-family="sans-serif">Reforma fiscal cripto de Japón — Actual vs. Propuesta</text>
  <g font-family="sans-serif">
    <rect x="30" y="55" width="290" height="230" rx="10" fill="#2a1414" stroke="#f87171" stroke-width="1.3"/>
    <text x="50" y="85" fill="#fca5a5" font-size="15" font-weight="700">Actual: ingreso vario agregado</text>
    <text x="50" y="118" fill="#e4e4e7" font-size="28" font-weight="700">Hasta 55%</text>
    <text x="50" y="145" fill="#a1a1aa" font-size="13">45% nacional + 10% residencial</text>
    <text x="50" y="170" fill="#a1a1aa" font-size="13">Progresivo, sumado a otros ingresos</text>
    <text x="50" y="195" fill="#a1a1aa" font-size="13">Sin traslado de pérdidas</text>
    <text x="50" y="250" fill="#71717a" font-size="12">Sin ETF posible (régimen PSA)</text>
    <rect x="380" y="55" width="290" height="230" rx="10" fill="#0e2a1e" stroke="#4ade80" stroke-width="1.3"/>
